    /**
     * Get all of M0_RFMT's bit fields.
     *
     * (read-write) Read transfer format configuration for memory address
     * window 0.
     *
     *                     Configure the bus width of each transfer phase
     * individually, and configure the length or presence of the command
     * prefix, command suffix and dummy/turnaround transfer phases. Only 24-bit
     * addresses are supported.
     *
     *                     The reset value of the M0_RFMT register is
     * configured to support a basic 03h serial read transfer with no
     * additional configuration.
     */
    inline void get_M0_RFMT(QMI_M0_RFMT_PREFIX_WIDTH &PREFIX_WIDTH,
                            QMI_M0_RFMT_ADDR_WIDTH &ADDR_WIDTH,
                            QMI_M0_RFMT_SUFFIX_WIDTH &SUFFIX_WIDTH,
                            QMI_M0_RFMT_DUMMY_WIDTH &DUMMY_WIDTH,
                            QMI_M0_RFMT_DATA_WIDTH &DATA_WIDTH,
                            bool &PREFIX_LEN,
                            QMI_M0_RFMT_SUFFIX_LEN &SUFFIX_LEN,
                            QMI_M0_RFMT_DUMMY_LEN &DUMMY_LEN,
                            bool &DTR) volatile
    {
        uint32_t curr = M0_RFMT;

        PREFIX_WIDTH = QMI_M0_RFMT_PREFIX_WIDTH(curr & 0b11u);
        ADDR_WIDTH = QMI_M0_RFMT_ADDR_WIDTH((curr >> 2u) & 0b11u);
        SUFFIX_WIDTH = QMI_M0_RFMT_SUFFIX_WIDTH((curr >> 4u) & 0b11u);
        DUMMY_WIDTH = QMI_M0_RFMT_DUMMY_WIDTH((curr >> 6u) & 0b11u);
        DATA_WIDTH = QMI_M0_RFMT_DATA_WIDTH((curr >> 8u) & 0b11u);
        PREFIX_LEN = curr & (1u << 12u);
        SUFFIX_LEN = QMI_M0_RFMT_SUFFIX_LEN((curr >> 14u) & 0b11u);
        DUMMY_LEN = QMI_M0_RFMT_DUMMY_LEN((curr >> 16u) & 0b111u);
        DTR = curr & (1u << 28u);
    }

    /**
     * Set all of M0_RFMT's bit fields.
     *
     * (read-write) Read transfer format configuration for memory address
     * window 0.
     *
     *                     Configure the bus width of each transfer phase
     * individually, and configure the length or presence of the command
     * prefix, command suffix and dummy/turnaround transfer phases. Only 24-bit
     * addresses are supported.
     *
     *                     The reset value of the M0_RFMT register is
     * configured to support a basic 03h serial read transfer with no
     * additional configuration.
     */
    inline void set_M0_RFMT(QMI_M0_RFMT_PREFIX_WIDTH PREFIX_WIDTH,
                            QMI_M0_RFMT_ADDR_WIDTH ADDR_WIDTH,
                            QMI_M0_RFMT_SUFFIX_WIDTH SUFFIX_WIDTH,
                            QMI_M0_RFMT_DUMMY_WIDTH DUMMY_WIDTH,
                            QMI_M0_RFMT_DATA_WIDTH DATA_WIDTH, bool PREFIX_LEN,
                            QMI_M0_RFMT_SUFFIX_LEN SUFFIX_LEN,
                            QMI_M0_RFMT_DUMMY_LEN DUMMY_LEN, bool DTR) volatile
    {
        uint32_t curr = M0_RFMT;

        curr &= ~(0b11u);
        curr |= (std::to_underlying(PREFIX_WIDTH) & 0b11u);
        curr &= ~(0b11u << 2u);
        curr |= (std::to_underlying(ADDR_WIDTH) & 0b11u) << 2u;
        curr &= ~(0b11u << 4u);
        curr |= (std::to_underlying(SUFFIX_WIDTH) & 0b11u) << 4u;
        curr &= ~(0b11u << 6u);
        curr |= (std::to_underlying(DUMMY_WIDTH) & 0b11u) << 6u;
        curr &= ~(0b11u << 8u);
        curr |= (std::to_underlying(DATA_WIDTH) & 0b11u) << 8u;
        curr &= ~(0b1u << 12u);
        curr |= (PREFIX_LEN & 0b1u) << 12u;
        curr &= ~(0b11u << 14u);
        curr |= (std::to_underlying(SUFFIX_LEN) & 0b11u) << 14u;
        curr &= ~(0b111u << 16u);
        curr |= (std::to_underlying(DUMMY_LEN) & 0b111u) << 16u;
        curr &= ~(0b1u << 28u);
        curr |= (DTR & 0b1u) << 28u;

        M0_RFMT = curr;
    }

