    /**
     * Get M1_TIMING's COOLDOWN field.
     *
     * Chip select cooldown period. When a memory transfer finishes, the chip
     * select remains asserted for 64 x COOLDOWN system clock cycles, plus half
     * an SCK clock period (rounded up for odd SCK divisors). After this
     * cooldown expires, the chip select is always deasserted to save power.
     *
     *                             If the next memory access arrives within the
     * cooldown period, the QMI may be able to append more SCK cycles to the
     * currently ongoing SPI transfer, rather than starting a new transfer.
     * This reduces access latency and increases bus throughput.
     *
     *                             Specifically, the next access must be in the
     * same direction (read/write), access the same memory window (chip select
     * 0/1), and follow sequentially the address of the last transfer. If any
     * of these are false, the new access will first deassert the chip select,
     * then begin a new transfer.
     *
     *                             If COOLDOWN is 0, the address alignment
     * configured by PAGEBREAK has been reached, or the total chip select
     * assertion limit MAX_SELECT has been reached, the cooldown period is
     * skipped, and the chip select will always be deasserted one half SCK
     * period after the transfer finishes.
     */
    inline uint8_t get_M1_TIMING_COOLDOWN() volatile
    {
        return (M1_TIMING >> 30u) & 0b11u;
    }

    /**
     * Set M1_TIMING's COOLDOWN field.
     *
     * Chip select cooldown period. When a memory transfer finishes, the chip
     * select remains asserted for 64 x COOLDOWN system clock cycles, plus half
     * an SCK clock period (rounded up for odd SCK divisors). After this
     * cooldown expires, the chip select is always deasserted to save power.
     *
     *                             If the next memory access arrives within the
     * cooldown period, the QMI may be able to append more SCK cycles to the
     * currently ongoing SPI transfer, rather than starting a new transfer.
     * This reduces access latency and increases bus throughput.
     *
     *                             Specifically, the next access must be in the
     * same direction (read/write), access the same memory window (chip select
     * 0/1), and follow sequentially the address of the last transfer. If any
     * of these are false, the new access will first deassert the chip select,
     * then begin a new transfer.
     *
     *                             If COOLDOWN is 0, the address alignment
     * configured by PAGEBREAK has been reached, or the total chip select
     * assertion limit MAX_SELECT has been reached, the cooldown period is
     * skipped, and the chip select will always be deasserted one half SCK
     * period after the transfer finishes.
     */
    inline void set_M1_TIMING_COOLDOWN(uint8_t value) volatile
    {
        uint32_t curr = M1_TIMING;

        curr &= ~(0b11u << 30u);
        curr |= (value & 0b11u) << 30u;

        M1_TIMING = curr;
    }

    /**
     * Get all of M1_TIMING's bit fields.
     *
     * (read-write) Timing configuration register for memory address window 1.
     */
    inline void get_M1_TIMING(uint8_t &CLKDIV, uint8_t &RXDELAY,
                              uint8_t &MIN_DESELECT, uint8_t &MAX_SELECT,
                              uint8_t &SELECT_HOLD, bool &SELECT_SETUP,
                              QMI_M1_TIMING_PAGEBREAK &PAGEBREAK,
                              uint8_t &COOLDOWN) volatile
    {
        uint32_t curr = M1_TIMING;

        CLKDIV = curr & 0xffu;
        RXDELAY = (curr >> 8u) & 0b111u;
        MIN_DESELECT = (curr >> 12u) & 0b11111u;
        MAX_SELECT = (curr >> 17u) & 0b111111u;
        SELECT_HOLD = (curr >> 23u) & 0b11u;
        SELECT_SETUP = curr & (1u << 25u);
        PAGEBREAK = QMI_M1_TIMING_PAGEBREAK((curr >> 28u) & 0b11u);
        COOLDOWN = (curr >> 30u) & 0b11u;
    }

    /**
     * Set all of M1_TIMING's bit fields.
     *
     * (read-write) Timing configuration register for memory address window 1.
     */
    inline void set_M1_TIMING(uint8_t CLKDIV, uint8_t RXDELAY,
                              uint8_t MIN_DESELECT, uint8_t MAX_SELECT,
                              uint8_t SELECT_HOLD, bool SELECT_SETUP,
                              QMI_M1_TIMING_PAGEBREAK PAGEBREAK,
                              uint8_t COOLDOWN) volatile
    {
        uint32_t curr = M1_TIMING;

        curr &= ~(0xffu);
        curr |= (CLKDIV & 0xffu);
        curr &= ~(0b111u << 8u);
        curr |= (RXDELAY & 0b111u) << 8u;
        curr &= ~(0b11111u << 12u);
        curr |= (MIN_DESELECT & 0b11111u) << 12u;
        curr &= ~(0b111111u << 17u);
        curr |= (MAX_SELECT & 0b111111u) << 17u;
        curr &= ~(0b11u << 23u);
        curr |= (SELECT_HOLD & 0b11u) << 23u;
        curr &= ~(0b1u << 25u);
        curr |= (SELECT_SETUP & 0b1u) << 25u;
        curr &= ~(0b11u << 28u);
        curr |= (std::to_underlying(PAGEBREAK) & 0b11u) << 28u;
        curr &= ~(0b11u << 30u);
        curr |= (COOLDOWN & 0b11u) << 30u;

        M1_TIMING = curr;
    }

