    /**
     * Get M1_RFMT's DTR bit.
     *
     * Enable double transfer rate (DTR) for read commands: address, suffix and
     * read data phases are active on both edges of SCK. SDO data is launched
     * centre-aligned on each SCK edge, and SDI data is captured on the SCK
     * edge that follows its launch.
     *
     *                             DTR is implemented by halving the clock
     * rate; SCK has a period of 2 x CLK_DIV throughout the transfer. The
     * prefix and dummy phases are still single transfer rate.
     *
     *                             If the suffix is quad-width, it must be 0 or
     * 8 bits in length, to ensure an even number of SCK edges.
     */
    inline bool get_M1_RFMT_DTR() volatile
    {
        return M1_RFMT & (1u << 28u);
    }

