    /**
     * Set all of M1_WFMT's bit fields.
     *
     * (read-write) Write transfer format configuration for memory address
     * window 1.
     *
     *                     Configure the bus width of each transfer phase
     * individually, and configure the length or presence of the command
     * prefix, command suffix and dummy/turnaround transfer phases. Only 24-bit
     * addresses are supported.
     *
     *                     The reset value of the M1_WFMT register is
     * configured to support a basic 02h serial write transfer. However, writes
     * to this window must first be enabled via the XIP_CTRL_WRITABLE_M1 bit,
     * as XIP memory is read-only by default.
     */
    inline void set_M1_WFMT(QMI_M1_WFMT_PREFIX_WIDTH PREFIX_WIDTH,
                            QMI_M1_WFMT_ADDR_WIDTH ADDR_WIDTH,
                            QMI_M1_WFMT_SUFFIX_WIDTH SUFFIX_WIDTH,
                            QMI_M1_WFMT_DUMMY_WIDTH DUMMY_WIDTH,
                            QMI_M1_WFMT_DATA_WIDTH DATA_WIDTH, bool PREFIX_LEN,
                            QMI_M1_WFMT_SUFFIX_LEN SUFFIX_LEN,
                            QMI_M1_WFMT_DUMMY_LEN DUMMY_LEN, bool DTR) volatile
    {
        uint32_t curr = M1_WFMT;

        curr &= ~(0b11u);
        curr |= (std::to_underlying(PREFIX_WIDTH) & 0b11u);
        curr &= ~(0b11u << 2u);
        curr |= (std::to_underlying(ADDR_WIDTH) & 0b11u) << 2u;
        curr &= ~(0b11u << 4u);
        curr |= (std::to_underlying(SUFFIX_WIDTH) & 0b11u) << 4u;
        curr &= ~(0b11u << 6u);
        curr |= (std::to_underlying(DUMMY_WIDTH) & 0b11u) << 6u;
        curr &= ~(0b11u << 8u);
        curr |= (std::to_underlying(DATA_WIDTH) & 0b11u) << 8u;
        curr &= ~(0b1u << 12u);
        curr |= (PREFIX_LEN & 0b1u) << 12u;
        curr &= ~(0b11u << 14u);
        curr |= (std::to_underlying(SUFFIX_LEN) & 0b11u) << 14u;
        curr &= ~(0b111u << 16u);
        curr |= (std::to_underlying(DUMMY_LEN) & 0b111u) << 16u;
        curr &= ~(0b1u << 28u);
        curr |= (DTR & 0b1u) << 28u;

        M1_WFMT = curr;
    }

